import { css } from '@emotion/react';

const StyledProductList = css`
  .container {
    width: 1020px;
    min-height: 100vh;
    margin: 0 auto;
    padding: 40px 0;
    > h3 {
      color: #444;
      font-size: 18px;
      font-weight: 100;
    }
    > h4 {
      font-weight: 600;
    }
  }
  .list {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    margin: 40px 0;
  }
`;

export default StyledProductList;
